<?php
require_once __DIR__.'/../lib/admin_auth.php'; require_once __DIR__.'/../lib/location_hours.php'; require_once __DIR__.'/../lib/admin_review.php'; craftcrawl_require_admin(); include '../db.php';
$id=filter_var($_GET['id']??null,FILTER_VALIDATE_INT); if(!$id) craftcrawl_redirect('admin/review_center.php');
$stmt=$conn->prepare("SELECT id,name FROM locations WHERE id=?");$stmt->bind_param('i',$id);$stmt->execute();$location=$stmt->get_result()->fetch_assoc(); if(!$location)craftcrawl_redirect('admin/review_center.php');
$hours=craftcrawl_location_hours_for_form($conn,$id); $message=null;
if($_SERVER['REQUEST_METHOD']==='POST'){craftcrawl_verify_csrf();$hours=craftcrawl_business_hours_from_post($_POST);$err=craftcrawl_validate_business_hours($hours);if($err){$message=$err;}else{$conn->begin_transaction();craftcrawl_save_location_hours($conn,$id,$hours,'admin_manual');$u=$conn->prepare("UPDATE location_hours SET verifiedAt=NOW(),verifiedByAdminId=? WHERE location_id=?");$u->bind_param('ii',$_SESSION['admin_id'],$id);$u->execute();craftcrawl_log_admin_review_action($conn,(int)$_SESSION['admin_id'],'location',$id,'approved','Hours verified');$conn->commit();craftcrawl_redirect('admin/review_center.php?message=hours_saved');}}
?>
<!doctype html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Edit Location Hours</title><link rel="stylesheet" href="../css/style.css?v=<?php echo filemtime(__DIR__.'/../css/style.css');?>"></head><body><main class="business-portal admin-page"><a href="review_center.php">Back</a><h1><?php echo craftcrawl_admin_escape($location['name']);?> Hours</h1><?php if($message):?><p class="form-message form-message-error"><?php echo craftcrawl_admin_escape($message);?></p><?php endif;?><form method="POST"><?php echo craftcrawl_csrf_input();?><fieldset class="business-hours-editor"><?php foreach($hours as $day=>$h):?><div class="business-hours-row"><span><?php echo craftcrawl_admin_escape($h['day_label']);?></span><label><input type="checkbox" name="hours_closed[<?php echo $day;?>]" value="1" <?php echo $h['is_closed']?'checked':'';?>>Closed</label><label>Opens<input type="time" name="hours_open[<?php echo $day;?>]" value="<?php echo craftcrawl_admin_escape($h['opens_at']);?>"></label><label>Closes<input type="time" name="hours_close[<?php echo $day;?>]" value="<?php echo craftcrawl_admin_escape($h['closes_at']);?>"></label></div><?php endforeach;?></fieldset><button>Save verified hours</button></form></main></body></html>
